27	entity top_tb is
28		generic (
29			OutputType_g	: string 	:= "AXIMM"
30		);
31	end entity top_tb;
32	
33	architecture sim of top_tb is
34	
35		-------------------------------------------------------------------------
36		-- AXI Definition
37		-------------------------------------------------------------------------
38		constant ID_WIDTH		: integer	:= 1;
39		constant ADDR_WIDTH		: integer	:= 8;
40		constant USER_WIDTH		: integer	:= 1;
41		constant DATA_WIDTH		: integer	:= 32;
42		constant BYTE_WIDTH		: integer	:= DATA_WIDTH/8;
43		
44		subtype ID_RANGE is natural range ID_WIDTH-1 downto 0;
45		subtype ADDR_RANGE is natural range ADDR_WIDTH-1 downto 0;
46		subtype USER_RANGE is natural range USER_WIDTH-1 downto 0;
47		subtype DATA_RANGE is natural range DATA_WIDTH-1 downto 0;
48		subtype BYTE_RANGE is natural range BYTE_WIDTH-1 downto 0;
49		
50		signal axi_ms : axi_ms_r (	arid(ID_RANGE), awid(ID_RANGE),
51									araddr(ADDR_RANGE), awaddr(ADDR_RANGE),
52									aruser(USER_RANGE), awuser(USER_RANGE), wuser(USER_RANGE),
53									wdata(DATA_RANGE),
54									wstrb(BYTE_RANGE));
55		
56		signal axi_sm : axi_sm_r (	rid(ID_RANGE), bid(ID_RANGE),
57									ruser(USER_RANGE), buser(USER_RANGE),
58									rdata(DATA_RANGE));
59									
60		signal axi_ms_m : axi_ms_r (	arid(ID_RANGE), awid(ID_RANGE),
61										araddr(31 downto 0), awaddr(31 downto 0),
62										aruser(USER_RANGE), awuser(USER_RANGE), wuser(USER_RANGE),
63										wdata(31 downto 0),
64										wstrb(3 downto 0));
65		
66		signal axi_sm_m : axi_sm_r (	rid(ID_RANGE), bid(ID_RANGE),
67										ruser(USER_RANGE), buser(USER_RANGE),
68										rdata(31 downto 0));
69	
70	
71		-------------------------------------------------------------------------
72		-- TB Defnitions
73		-------------------------------------------------------------------------
74		constant	ClockFrequencyAxi_c	: real		:= 125.0e6;							-- Use slow clocks to speed up simulation
75		constant	ClockPeriodAxi_c	: time		:= (1 sec)/ClockFrequencyAxi_c;
76		signal		TbRunning			: boolean	:= True;
77		signal		StimCase			: integer	:= -1;
78		signal 		RespCase			: integer	:= -1;
79	
80		
81		-------------------------------------------------------------------------
82		-- Interface Signals
83		-------------------------------------------------------------------------
84		signal aclk				: std_logic							:= '0';
85		signal aresetn			: std_logic							:= '0';
86		signal areset 			: std_logic							:= '1';
87		signal Trig				: std_logic							:= '0';
88		signal DoneIrq			: std_logic							:= '0';
89		signal m_axis_tdata		: std_logic_vector(31 downto 0);
90		signal m_axis_tvalid	: std_logic;
91		signal m_axis_tready	: std_logic 						:= '0';
92		signal m_axis_tlast		: std_logic;
93	
94	
95		-- *** Procedures ***
96		procedure CheckResultsAxiS(	start 					: in integer; 
97									step 					: in integer;
98									signal vld				: in std_logic;
99									signal rdy				: out std_logic;
100									signal last				: in std_logic;
101									signal data				: in std_logic_vector;
102									signal clk				: in std_logic) is
103		begin
104			rdy <= '1';
105			for i in 0 to 13 loop
106				wait until rising_edge(clk) and vld = '1';
107				StdlvCompareInt (start+i*step, data, "Data");
108				StdlCompare(choose(i=13,1,0), last, "Wrong Tlast");
109			end loop;
110			rdy <= '0';
111		end procedure;
112		
113		procedure CheckResultsAxiMM(	start 					: in integer; 
114										step 					: in integer;
115										signal axi_ms			: out axi_ms_r;
116										signal axi_sm			: in axi_sm_r;
117										signal clk				: in std_logic) is
118			variable x : integer;
119		begin
120			for i in 0 to 13 loop
121				-- Wait until data available
122				loop
123					axi_single_read(RegIdx_Level_c*4, x, axi_ms, axi_sm, clk);
124					if x > 0 then
125						exit;
126					end if;
127				end loop;
128					
129				-- Check last
130				axi_single_expect(RegIdx_RdLast_c*4, choose(i=13,1,0), axi_ms, axi_sm, clk, "Last");
131				axi_single_expect(RegIdx_RdData_c*4, start+i*step, axi_ms, axi_sm, clk, "Data " & to_string(i));
132			end loop;
133		end procedure;
134		
135		procedure CheckResults(	start 					: in integer; 
136								step 					: in integer;
137								signal vld				: in std_logic;
138								signal rdy				: out std_logic;
139								signal last				: in std_logic;
140								signal data				: in std_logic_vector;
141								signal axi_ms			: out axi_ms_r;
142								signal axi_sm			: in axi_sm_r;
143								signal clk				: in std_logic) is
144		begin
145			if OutputType_g = "AXIS" then
146				CheckResultsAxiS(start, step, vld, rdy, last, data, clk);
147			else
148				CheckResultsAxiMM(start, step, axi_ms, axi_sm, clk);
149			end if;
150		end procedure;
151	begin
152	
153		areset <= not aresetn;
154		-------------------------------------------------------------------------
155		-- DUT
156		-------------------------------------------------------------------------
157		i_dut : entity work.axi_mm_reader_wrp
158			generic map (
159				ClkFrequencyHz		=> integer(ClockFrequencyAxi_c),
160				TimeoutUs_g			=> 10,
161				MaxRegCount_g		=> 16,
162				MinBuffers_g		=> 2,
163				Output_g			=> OutputType_g,
164				AxiSlaveAddrWidth_g => 8
165			)
166			port map (
167				Clk					=> aclk,
168				Rst					=> areset,
169				Trig				=> Trig,
170				DoneIrq				=> DoneIrq,
171				s00_axi_arid		=> axi_ms.arid,
172				s00_axi_araddr		=> axi_ms.araddr,
173				s00_axi_arlen		=> axi_ms.arlen,
174				s00_axi_arsize		=> axi_ms.arsize,
175				s00_axi_arburst		=> axi_ms.arburst,
176				s00_axi_arlock		=> axi_ms.arlock,
177				s00_axi_arcache		=> axi_ms.arcache,
178				s00_axi_arprot		=> axi_ms.arprot,
179				s00_axi_arvalid		=> axi_ms.arvalid,
180				s00_axi_arready		=> axi_sm.arready,
181				s00_axi_rid			=> axi_sm.rid,
182				s00_axi_rdata		=> axi_sm.rdata,
183				s00_axi_rresp		=> axi_sm.rresp,
184				s00_axi_rlast		=> axi_sm.rlast,
185				s00_axi_rvalid		=> axi_sm.rvalid,
186				s00_axi_rready		=> axi_ms.rready,
187				s00_axi_awid		=> axi_ms.awid,
188				s00_axi_awaddr		=> axi_ms.awaddr,
189				s00_axi_awlen		=> axi_ms.awlen,
190				s00_axi_awsize		=> axi_ms.awsize,
191				s00_axi_awburst		=> axi_ms.awburst,
192				s00_axi_awlock		=> axi_ms.awlock,
193				s00_axi_awcache		=> axi_ms.awcache,
194				s00_axi_awprot		=> axi_ms.awprot,
195				s00_axi_awvalid		=> axi_ms.awvalid,
196				s00_axi_awready		=> axi_sm.awready,
197				s00_axi_wdata		=> axi_ms.wdata,
198				s00_axi_wstrb		=> axi_ms.wstrb,
199				s00_axi_wlast		=> axi_ms.wlast,
200				s00_axi_wvalid		=> axi_ms.wvalid,
201				s00_axi_wready		=> axi_sm.wready,
202				s00_axi_bid			=> axi_sm.bid,
203				s00_axi_bresp		=> axi_sm.bresp,
204				s00_axi_bvalid		=> axi_sm.bvalid,
205				s00_axi_bready		=> axi_ms.bready,
206	
207				-----------------------------------------------------------------------------
208				-- Axi Master Bus Interface
209				-----------------------------------------------------------------------------
210				m00_axi_araddr		=> axi_ms_m.araddr,
211				m00_axi_arlen		=> axi_ms_m.arlen,
212				m00_axi_arsize		=> axi_ms_m.arsize,
213				m00_axi_arburst		=> axi_ms_m.arburst,
214				m00_axi_arlock		=> axi_ms_m.arlock,
215				m00_axi_arcache		=> axi_ms_m.arcache,
216				m00_axi_arprot		=> axi_ms_m.arprot,
217				m00_axi_arvalid		=> axi_ms_m.arvalid,
218				m00_axi_arready		=> axi_sm_m.arready,
219				m00_axi_rdata		=> axi_sm_m.rdata,
220				m00_axi_rresp		=> axi_sm_m.rresp,
221				m00_axi_rlast		=> axi_sm_m.rlast,
222				m00_axi_rvalid		=> axi_sm_m.rvalid,
223				m00_axi_rready		=> axi_ms_m.rready,
224	
225				-----------------------------------------------------------------------------
226				-- Stream Output
227				-----------------------------------------------------------------------------
228				m_axis_tdata		=> m_axis_tdata,
229				m_axis_tvalid		=> m_axis_tvalid,
230				m_axis_tready		=> m_axis_tready,
231				m_axis_tlast		=> m_axis_tlast
232			);
233	
234		
235		-------------------------------------------------------------------------
236		-- Clock
237		-------------------------------------------------------------------------
238		p_aclk : process
239		begin
240			aclk <= '0';
241			while TbRunning loop
242				wait for 0.5*ClockPeriodAxi_c;
243				aclk <= '1';
244				wait for 0.5*ClockPeriodAxi_c;
245				aclk <= '0';
246			end loop;
247			wait;
248		end process;
249		
250		-------------------------------------------------------------------------
251		-- TB Control
252		-------------------------------------------------------------------------
253		p_control : process
254			variable x	: integer;
255		begin
256			-- Reset
257			aresetn <= '0';
258			wait for 1 us;
259			wait until rising_edge(aclk);
260			aresetn <= '1';
261			wait for 1 us;
262			wait until rising_edge(aclk);
263			
264			-- *** Setup for reading 14 registers ***		
265			axi_single_write(RegIdx_RegCnt_c*4, 14, axi_ms, axi_sm, aclk);
266			for i in 0 to 13 loop
267				axi_single_write((MemOffs_c+i)*4, 16#00AB0000#+16*i, axi_ms, axi_sm, aclk);
268			end loop;		
269			axi_single_write(RegIdx_Ctrl_c*4, 1, axi_ms, axi_sm, aclk);
270			
271			-- *** Trigger Single Read ***
272			print(">> Trigger Single Read");
273			StimCase <= 1;
274			ClockedWaitTime(100 ns, aclk);
275			PulseSig(Trig, aclk);
276			CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
277			wait until rising_edge(aclk) and RespCase = 1;
278	
279			-- *** Buffered Double Read ***
280			print(">> Buffered Double Read");
281			StimCase <= 2;
282			axi_single_expect(RegIdx_Level_c*4, 0, axi_ms, axi_sm, aclk);
283			ClockedWaitTime(100 ns, aclk);
284			PulseSig(Trig, aclk);
285			ClockedWaitTime(1 us, aclk);
286			PulseSig(Trig, aclk);
287			ClockedWaitTime(1 us, aclk);
288			axi_single_expect(RegIdx_Level_c*4, 14*2, axi_ms, axi_sm, aclk);
289			CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
290			CheckResults(32, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
291			wait until rising_edge(aclk) and RespCase = 2;
292			
293			-- *** Timeout ***
294			print(">> Timeout");
295			StimCase <= 3;
296			if OutputType_g = "AXIS" then
297				CheckNoActivity(m_axis_tvalid, 8 us, 0, "Timeout interrupted");		
298				WaitForValueStdl(m_axis_tvalid, '1', 3 us, "Timout not occurred");
299			else
300				ClockedWaitTime(5 us, aclk);
301				axi_single_expect(RegIdx_Level_c*4, 0, axi_ms, axi_sm, aclk);
302				-- Wait until data available
303				loop
304					axi_single_read(RegIdx_Level_c*4, x, axi_ms, axi_sm, aclk);
305					if x > 0 then
306						exit;
307					end if;
308				end loop;
309			end if;
310			CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
311			wait until rising_edge(aclk) and RespCase = 3;
312			
313			-- *** Test Disabled ***
314			print(">> Disabled");
315			StimCase <= 4;
316			axi_single_write(RegIdx_Ctrl_c*4, 0, axi_ms, axi_sm, aclk);
317			ClockedWaitTime(100 ns, aclk);
318			PulseSig(Trig, aclk);
319			CheckNoActivity(m_axis_tvalid, 12 us, 0, "Timeout interrupted");
320			axi_single_write(RegIdx_Ctrl_c*4, 1, axi_ms, axi_sm, aclk);
321			CheckNoActivity(m_axis_tvalid, 2 us, 0, "Timeout interrupted");
322			wait until rising_edge(aclk) and RespCase = 4;
323			
324			-- *** Back Pressure ***
325			print(">> Back Pressure");
326			StimCase <= 5;
327			ClockedWaitTime(100 ns, aclk);
328			-- Trigger too often, creating back pressure
329			for i in 0 to 5 loop
330				PulseSig(Trig, aclk);
331				ClockedWaitTime(1 us, aclk);
332			end loop;
333			-- Check one frame and start next
334			ClockedWaitTime(1 us, aclk);
335			CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
336			PulseSig(Trig, aclk);
337			ClockedWaitTime(1 us, aclk);
338			axi_single_write(RegIdx_Ctrl_c*4, 0, axi_ms, axi_sm, aclk);
339			-- Check remainig frames (all are complete)
340			if OutputType_g = "AXIS" then
341				while m_axis_tvalid = '1' loop
342					CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
343					ClockedWaitTime(20 ns, aclk);
344				end loop;
345			else
346				loop
347					axi_single_read(RegIdx_Level_c*4, x, axi_ms, axi_sm, aclk);
348					if x = 0 then
349						exit;
350					end if;
351					CheckResults(0, 1, m_axis_tvalid, m_axis_tready, m_axis_tlast, m_axis_tdata, axi_ms, axi_sm, aclk);
352				end loop;
353			end if;
354			axi_single_write(RegIdx_Ctrl_c*4, 1, axi_ms, axi_sm, aclk);
355			wait until rising_edge(aclk) and RespCase = 5;
356			
357			-- *** Single Reg Read Four Times ***
358			print(">> Single Reg Read Four Time");
359			StimCase <= 6;
360			axi_single_write(RegIdx_RegCnt_c*4, 1, axi_ms, axi_sm, aclk);
361			for i in 0 to 3 loop
362				ClockedWaitTime(100 ns, aclk);
363				PulseSig(Trig, aclk);
364			end loop;
365			ClockedWaitTime(1 us, aclk);
366			if OutputType_g = "AXIS" then
367				m_axis_tready <= '1';
368				for i in 0 to 3 loop	
369					wait until m_axis_tvalid = '1' and rising_edge(aclk);		
370					StdlvCompareInt (i, m_axis_tdata, "Data");
371					StdlCompare(1, m_axis_tlast, "Wrong Tlast");
372				end loop;
373				m_axis_tready <= '0';
374			else
375				for i in 0 to 3 loop	
376					-- Wait until data available
377					loop
378						axi_single_read(RegIdx_Level_c*4, x, axi_ms, axi_sm, aclk);
379						if x > 0 then
380							exit;
381						end if;
382					end loop;
383					-- Check
384					axi_single_expect(RegIdx_RdLast_c*4, 1, axi_ms, axi_sm, aclk, "Last");
385					axi_single_expect(RegIdx_RdData_c*4, i, axi_ms, axi_sm, aclk, "Data " & to_string(i));
386				end loop;
387			end if;			
388			wait until rising_edge(aclk) and RespCase = 6;
389	
390			
391			-- TB done
392			wait for 1 us;
393			TbRunning <= false;
394			wait;
395		end process;
396		
397		-------------------------------------------------------------------------
398		-- SPI Emulation
399		-------------------------------------------------------------------------
400		p_spi : process
401			constant TransWidth_c	: integer := 8;
402			constant SpiCPHA_c		: integer := 0;
403			constant SpiCPOL_c		: integer := 0;
404			constant LsbFirst_c		: boolean := false;
405			variable ShiftRegRx_v	: std_logic_vector(TransWidth_c-1 downto 0);
406			variable ShiftRegTx_v	: std_logic_vector(TransWidth_c-1 downto 0);
407			variable ExpLatch_v		: std_logic_vector(TransWidth_c-1 downto 0);
408		begin	
409			wait until aresetn = '1';
410			wait until rising_edge(aclk);
411			
412			-- *** Trigger Single Read ***
413			wait until rising_edge(aclk) and StimCase = 1;
414			for i in 0 to 13 loop
415				axi_expect_ar(16#00AB0000#+16*i, AxSIZE_4_c, 0, xBURST_INCR_c, axi_ms_m, axi_sm_m, aclk);
416				axi_apply_rresp_single(std_logic_vector(to_unsigned(i, 32)), xRESP_OKAY_c, axi_ms_m, axi_sm_m, aclk);
417			end loop;
418			RespCase <= 1;
419			
420			-- *** Buffered Double Read ***
421			wait until rising_edge(aclk) and StimCase = 2;
422			for x in 0 to 1 loop
423				for i in 0 to 13 loop
424					axi_expect_ar(16#00AB0000#+16*i, AxSIZE_4_c, 0, xBURST_INCR_c, axi_ms_m, axi_sm_m, aclk);
425					axi_apply_rresp_single(std_logic_vector(to_unsigned(i+x*32, 32)), xRESP_OKAY_c, axi_ms_m, axi_sm_m, aclk);
426				end loop;
427			end loop;
428			RespCase <= 2;
429			
430			-- *** Timeout ***
431			wait until rising_edge(aclk) and StimCase = 3;
432			for i in 0 to 13 loop
433				axi_expect_ar(16#00AB0000#+16*i, AxSIZE_4_c, 0, xBURST_INCR_c, axi_ms_m, axi_sm_m, aclk);
434				axi_apply_rresp_single(std_logic_vector(to_unsigned(i, 32)), xRESP_OKAY_c, axi_ms_m, axi_sm_m, aclk);
435			end loop;
436			RespCase <= 3;
437			
438			-- *** Test Disabled ***
439			wait until rising_edge(aclk) and StimCase = 4;
440			RespCase <= 4;
441			
442			-- *** Test Back Pressure ***
443			wait until rising_edge(aclk) and StimCase = 5;
444			loop
445				wait until axi_ms_m.arvalid = '1' and rising_edge(aclk) for 10 us;
446				if axi_ms_m.arvalid = '0' then
447					exit;
448				end if;
449				for i in 0 to 13 loop
450					axi_expect_ar(16#00AB0000#+16*i, AxSIZE_4_c, 0, xBURST_INCR_c, axi_ms_m, axi_sm_m, aclk);
451					axi_apply_rresp_single(std_logic_vector(to_unsigned(i, 32)), xRESP_OKAY_c, axi_ms_m, axi_sm_m, aclk);
452				end loop;
453			end loop;
454			RespCase <= 5;
455			
456			-- *** Single Reg Read Four Times ***
457			wait until rising_edge(aclk) and StimCase = 6;
458			for i in 0 to 3 loop
459				axi_expect_ar(16#00AB0000#, AxSIZE_4_c, 0, xBURST_INCR_c, axi_ms_m, axi_sm_m, aclk);
460				axi_apply_rresp_single(std_logic_vector(to_unsigned(i, 32)), xRESP_OKAY_c, axi_ms_m, axi_sm_m, aclk);
461			end loop;
462			RespCase <= 6;
463	
464			wait;
465			
466		end process;
467		
468		
469	
470	end sim;
